-- Malpica / Tahifed full price-list import for Nancy's Castalla
-- Source: C:\Users\jim\Downloads\nancys castalla\prijslijsten\malpicapuntocomprecio.pdf
-- Extracted rows: 301
-- Product numbers: NC-01280 through NC-01580
-- All products are inserted hidden from the public website: is_visible = false.
-- Prices from the PDF are treated as unit cost prices excluding IVA.
-- Sale prices are generated with a 50% margin ex IVA, then IVA is added.
-- IVA is read from the PDF. Review customer prices and categories before enabling online.

on conflict (id) do update set
  name = excluded.name,
  image_url = excluded.image_url,
  is_visible = excluded.is_visible,
  category = excluded.category,
  description = excluded.description,
  price = excluded.price,
  unit = excluded.unit,
  stock_status = excluded.stock_status,
  type = excluded.type,
  origin = excluded.origin,
  featured = excluded.featured,
  cost_price_ex_vat = excluded.cost_price_ex_vat,
  vat_rate = excluded.vat_rate,
  sale_price_incl_vat = excluded.sale_price_incl_vat,
  margin_percent = excluded.margin_percent,
  profit_per_unit = excluded.profit_per_unit,
  supplier = excluded.supplier,
  supplier_code = excluded.supplier_code,
  pack_size = excluded.pack_size,
  unit_cost = excluded.unit_cost,
  package_options = excluded.package_options,
  ingredients = excluded.ingredients,
  directions = excluded.directions,
  conservation = excluded.conservation,
  additional_info = excluded.additional_info;
